**Scenario 4: Multiple Images with Different Priorities**

```tsx
export default function ProductGallery({ images }) {
  return (
    <div className="grid grid-cols-3 gap-4">
      {images.map((img, index) => (
        <Image
          key={img.id}
          src={img.url}
          alt={img.alt}
          width={400}
          height={300}
          loading={index < 3 ? 'eager' : 'lazy'}  // First 3 eager
          priority={index === 0}  // First image priority
          placeholder="blur"
          blurDataURL={img.blurDataURL}
        />
      ))}
    </div>
  );
}
```

